import type { Meta, StoryObj } from '@storybook/react';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import { PixiCanvas } from '../PixiCanvas';
import { ThemeProvider } from '../../theme/ThemeProvider';
import { SCENARIOS } from '../../services/mock/generator';
import { loadScenarioIntoStore } from '../../services/mock/loader';
import type { FractalRenderer } from '../FractalRenderer';

/**
 * PixiCanvas with pixi-viewport for Google Maps style navigation.
 *
 * Features:
 * - Pan: Click and drag
 * - Zoom: Mouse wheel or pinch gesture
 * - Inertia: Release while dragging for momentum
 */
const meta: Meta<typeof PixiCanvas> = {
  title: 'Render/PixiCanvas',
  component: PixiCanvas,
  decorators: [
    (Story) => (
      <ThemeProvider>
        <Box sx={{ width: '100vw', height: '100vh', bgcolor: 'background.default' }}>
          <Story />
        </Box>
      </ThemeProvider>
    ),
  ],
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        component: 'WebGL canvas with pixi-viewport for pan/zoom/inertia navigation.',
      },
    },
  },
};

export default meta;
type Story = StoryObj<typeof PixiCanvas>;

/**
 * Default canvas with LOD layers and sample data.
 */
export const Default: Story = {
  render: () => {
    const handleReady = (renderer: FractalRenderer) => {
      const scenario = SCENARIOS.standard().generateScenario(12);
      loadScenarioIntoStore(scenario);
      console.log('[Story] Renderer ready, data loaded');
    };

    return (
      <Box sx={{ width: '100%', height: '100%', display: 'flex', flexDirection: 'column' }}>
        <Box sx={{ p: 2, bgcolor: 'background.paper', borderBottom: 1, borderColor: 'divider' }}>
          <Typography variant="h6">PixiCanvas with pixi-viewport</Typography>
          <Typography variant="caption" color="text.secondary">
            Pan: drag | Zoom: wheel/pinch | Inertia: release while dragging
          </Typography>
        </Box>
        <Box sx={{ flex: 1 }}>
          <PixiCanvas onReady={handleReady} />
        </Box>
      </Box>
    );
  },
};

/**
 * Canvas with debug overlay showing grid and LOD indicator.
 */
export const WithDebug: Story = {
  render: () => {
    const handleReady = (renderer: FractalRenderer) => {
      const scenario = SCENARIOS.standard().generateScenario(12);
      loadScenarioIntoStore(scenario);
    };

    return (
      <Box sx={{ width: '100%', height: '100%', display: 'flex', flexDirection: 'column' }}>
        <Box sx={{ p: 2, bgcolor: 'background.paper', borderBottom: 1, borderColor: 'divider' }}>
          <Typography variant="h6">Debug Mode</Typography>
          <Typography variant="caption" color="text.secondary">
            Shows grid overlay and LOD indicator (colored circle top-right)
          </Typography>
        </Box>
        <Box sx={{ flex: 1 }}>
          <PixiCanvas debug onReady={handleReady} />
        </Box>
      </Box>
    );
  },
};

/**
 * Empty canvas for testing viewport navigation without data.
 */
export const EmptyCanvas: Story = {
  render: () => {
    return (
      <Box sx={{ width: '100%', height: '100%', display: 'flex', flexDirection: 'column' }}>
        <Box sx={{ p: 2, bgcolor: 'background.paper', borderBottom: 1, borderColor: 'divider' }}>
          <Typography variant="h6">Empty Canvas</Typography>
          <Typography variant="caption" color="text.secondary">
            Test navigation without data - pan and zoom should still work
          </Typography>
        </Box>
        <Box sx={{ flex: 1 }}>
          <PixiCanvas />
        </Box>
      </Box>
    );
  },
};

